-- ===== BEGIN V1__create_user_profile.sql =====
-- USER_PROFILE: 사용자 입력/이력 (이력 불변 + 활성 플래그)
-- 정책:
-- - 같은 user_id에 대해 최신 유효 1건만 is_active='Y'
-- - 신규 입력 시 기존 is_active='Y'를 'N'으로 바꾸고 신규 row insert

CREATE TABLE USER_PROFILE (
    profile_id           NUMBER          NOT NULL,
    user_id              NUMBER          NOT NULL,
    input_level          NUMBER          NOT NULL,

    age                  NUMBER,
    income_year          NUMBER,
    gender               VARCHAR2(20),

    employment_type      VARCHAR2(50),
    residence_type       VARCHAR2(50),

    debt_total           NUMBER,
    existing_loan_count  NUMBER,
    loan_purpose         VARCHAR2(100),

    input_state_code     VARCHAR2(50),
    is_active            CHAR(1)         DEFAULT 'Y' NOT NULL,
    created_at           TIMESTAMP       DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_USER_PROFILE PRIMARY KEY (profile_id),
    CONSTRAINT CK_USER_PROFILE_ACTIVE CHECK (is_active IN ('Y','N')),
    CONSTRAINT CK_USER_PROFILE_LEVEL CHECK (input_level IN (1,2,3))
);

-- PK 시퀀스
CREATE SEQUENCE USER_PROFILE_SEQ
    START WITH 1
    INCREMENT BY 1
    NOCACHE
    NOCYCLE;

-- 조회 성능: 최신 유효 조회/이력 조회 지원
CREATE INDEX IDX_USER_PROFILE_USER_ACTIVE
    ON USER_PROFILE (user_id, is_active, created_at DESC);

CREATE INDEX IDX_USER_PROFILE_USER_CREATED
    ON USER_PROFILE (user_id, created_at DESC);
-- ===== END V1__create_user_profile.sql =====

-- ===== BEGIN V2__create_loan_product.sql =====
-- LOAN_PRODUCT: 대출상품(기본정보)
-- 정책:
-- - product_id는 시퀀스로 생성
-- - CODE_VALUE 기반 코드 컬럼은 code_value_id 문자열로 보관(v1)

CREATE TABLE LOAN_PRODUCT (
    product_id                   NUMBER           NOT NULL,
    provider_id                  NUMBER           NOT NULL,

    product_name                 VARCHAR2(200)    NOT NULL,

    product_type_code_value_id   VARCHAR2(50)     NOT NULL,
    loan_type_code_value_id      VARCHAR2(50)     NOT NULL,
    repayment_type_code_value_id VARCHAR2(50)     NOT NULL,

    collateral_type_code_value_id VARCHAR2(50),
    rate_type_code_value_id      VARCHAR2(50),

    note                         VARCHAR2(1000),

    add_date                     TIMESTAMP        DEFAULT SYSTIMESTAMP NOT NULL,
    end_date                     DATE,
    updated_at                   TIMESTAMP        DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_LOAN_PRODUCT PRIMARY KEY (product_id)
);

-- PK 시퀀스
CREATE SEQUENCE LOAN_PRODUCT_SEQ
    START WITH 1
    INCREMENT BY 1
    NOCACHE
    NOCYCLE;

-- 조회/정렬 성능
CREATE INDEX IDX_LOAN_PRODUCT_PROVIDER
    ON LOAN_PRODUCT (provider_id);

CREATE INDEX IDX_LOAN_PRODUCT_UPDATED
    ON LOAN_PRODUCT (updated_at DESC, add_date DESC);
-- ===== END V2__create_loan_product.sql =====

-- ===== BEGIN V3__create_user_consent.sql =====
-- USER_CONSENT: 사용자 LV별 동의 이력 (이력 불변 + 활성 플래그)
-- 정책:
-- - 같은 (user_id, consent_level) 조합에 대해 최신 유효 1건만 is_active='Y'
-- - 신규 입력 시 기존 is_active='Y'를 'N'으로 바꾸고 신규 row insert

CREATE TABLE USER_CONSENT (
    consent_id      NUMBER          NOT NULL,
    user_id         NUMBER          NOT NULL,
    consent_level   NUMBER          NOT NULL,  -- 1~3 (LV)
    consent_given   CHAR(1)         NOT NULL,  -- 'Y'/'N'
    is_active       CHAR(1)         DEFAULT 'Y' NOT NULL,
    created_at      TIMESTAMP       DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_USER_CONSENT PRIMARY KEY (consent_id),
    CONSTRAINT CK_USER_CONSENT_LEVEL CHECK (consent_level IN (1,2,3)),
    CONSTRAINT CK_USER_CONSENT_GIVEN CHECK (consent_given IN ('Y','N')),
    CONSTRAINT CK_USER_CONSENT_ACTIVE CHECK (is_active IN ('Y','N'))
);

-- PK 시퀀스
CREATE SEQUENCE USER_CONSENT_SEQ
    START WITH 1
    INCREMENT BY 1
    NOCACHE
    NOCYCLE;

-- 조회 성능: 최신 유효 조회 / 이력 조회
CREATE INDEX IDX_USER_CONSENT_USER_LEVEL_ACTIVE
    ON USER_CONSENT (user_id, consent_level, is_active, created_at DESC);

CREATE INDEX IDX_USER_CONSENT_USER_LEVEL_CREATED
    ON USER_CONSENT (user_id, consent_level, created_at DESC);
-- ===== END V3__create_user_consent.sql =====

-- ===== BEGIN V4__create_recommend_history.sql =====
-- RECOMMEND_HISTORY: 추천 이력(재현/감사/증거 경로 포함)
-- 정책:
-- - DB에는 JSON 자체 저장하지 않음 (경로만 저장)
-- - reproduce_key는 재현 키이므로 UNIQUE
-- - append-only 성격(삭제/갱신 최소화). v1에서는 update 사용하지 않음

CREATE TABLE RECOMMEND_HISTORY (
    recommend_id         NUMBER           NOT NULL,
    user_id              NUMBER           NOT NULL,

    reproduce_key        VARCHAR2(200)    NOT NULL,

    recommend_state      VARCHAR2(30)     NOT NULL,  -- READY / NOT_READY / BLOCKED

    policy_version       VARCHAR2(100),
    meta_version         VARCHAR2(100),

    evidence_file_path   VARCHAR2(1000),
    explain_file_path    VARCHAR2(1000),

    created_at           TIMESTAMP        DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_RECOMMEND_HISTORY PRIMARY KEY (recommend_id),
    CONSTRAINT UQ_RECOMMEND_HISTORY_REPRODUCE UNIQUE (reproduce_key)
);

-- PK 시퀀스
CREATE SEQUENCE RECOMMEND_HISTORY_SEQ
    START WITH 1
    INCREMENT BY 1
    NOCACHE
    NOCYCLE;

-- 조회 성능
CREATE INDEX IDX_RECOMMEND_HISTORY_USER
    ON RECOMMEND_HISTORY (user_id, created_at DESC);

CREATE INDEX IDX_RECOMMEND_HISTORY_STATE
    ON RECOMMEND_HISTORY (recommend_state, created_at DESC);
-- ===== END V4__create_recommend_history.sql =====

-- ===== BEGIN V5__create_core_erd.sql =====
-- 설계서 기준 ERD 핵심 테이블 (정식 마이그레이션)
-- 출처: `5. ERD.pdf`
-- 주의: 컬럼/자료형/제약은 ERD 상세 기준으로 추가 보정 필요
-- 대상 DB: Oracle (NUMBER, VARCHAR2, TIMESTAMP, DATE)

-- =====================================================
-- USER CREDIT (LV1/2/3)
-- =====================================================
CREATE TABLE USER_CREDIT_LV1 (
    user_id        NUMBER    NOT NULL, -- PK, FK -> USER_PROFILE.user_id
    age            NUMBER,
    income_year    NUMBER,
    gender         VARCHAR2(20),
    created_at     TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_USER_CREDIT_LV1 PRIMARY KEY (user_id)
);

CREATE TABLE USER_CREDIT_LV2 (
    user_id          NUMBER    NOT NULL, -- PK, FK -> USER_PROFILE.user_id
    employment_type  VARCHAR2(50),
    residence_type   VARCHAR2(50),
    created_at       TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_USER_CREDIT_LV2 PRIMARY KEY (user_id)
);

CREATE TABLE USER_CREDIT_LV3 (
    user_id              NUMBER    NOT NULL, -- PK, FK -> USER_PROFILE.user_id
    loan_purpose         VARCHAR2(100),
    total_debt           NUMBER,
    existing_loan_count  NUMBER,
    created_at           TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_USER_CREDIT_LV3 PRIMARY KEY (user_id)
);

-- =====================================================
-- CODE DICTIONARY (메타데이터)
-- =====================================================
CREATE TABLE CODE_DICTIONARY_VERSION (
    version_id      NUMBER       NOT NULL,
    upload_id       NUMBER,       -- FK -> RAW_FILE_UPLOAD.upload_id
    version_label   VARCHAR2(200),
    created_at      TIMESTAMP     DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_CODE_DICT_VERSION PRIMARY KEY (version_id)
);

CREATE TABLE CODE_DICTIONARY (
    dict_id            NUMBER       NOT NULL,
    version_id         NUMBER       NOT NULL, -- FK -> CODE_DICTIONARY_VERSION.version_id
    column_code        VARCHAR2(200),
    column_name        VARCHAR2(200),
    column_desc        VARCHAR2(1000),
    large_category_code_value_id  VARCHAR2(100),
    mideum_category_code_value_id VARCHAR2(100),
    small_category_code_value_id  VARCHAR2(100),
    is_required        CHAR(1),
    data_type          VARCHAR2(50),
    created_at         TIMESTAMP    DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_CODE_DICTIONARY PRIMARY KEY (dict_id)
);

CREATE TABLE CODE_DICTIONARY_DIFF (
    diff_id          NUMBER       NOT NULL,
    pre_version_id   NUMBER       NOT NULL, -- FK -> CODE_DICTIONARY_VERSION.version_id
    post_version_id  NUMBER       NOT NULL, -- FK -> CODE_DICTIONARY_VERSION.version_id
    change_type      VARCHAR2(20),
    column_code      VARCHAR2(200),
    before_json_path VARCHAR2(1000),
    after_json_path  VARCHAR2(1000),
    created_at       TIMESTAMP    DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_CODE_DICTIONARY_DIFF PRIMARY KEY (diff_id)
);

-- =====================================================
-- RECOMMENDATION CORE
-- =====================================================
CREATE TABLE RECO_POLICY (
    policy_id                NUMBER       NOT NULL,
    version                  VARCHAR2(100),
    policy_type_code_value_id VARCHAR2(100),
    policy_key               VARCHAR2(200),
    policy_value             VARCHAR2(2000),
    effective_from           TIMESTAMP,
    effective_to             TIMESTAMP,
    created_at               TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_RECO_POLICY PRIMARY KEY (policy_id)
);

CREATE TABLE RECO_REQUEST (
    request_id     NUMBER       NOT NULL,
    user_id        NUMBER       NOT NULL, -- FK -> USER_PROFILE.user_id
    version_id     NUMBER,       -- FK -> CODE_DICTIONARY_VERSION.version_id
    requested_at   TIMESTAMP     DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_RECO_REQUEST PRIMARY KEY (request_id)
);

CREATE TABLE RECO_RESULT (
    result_id               NUMBER       NOT NULL,
    request_id              NUMBER       NOT NULL, -- FK -> RECO_REQUEST.request_id
    overall_score           NUMBER,
    policy_version          VARCHAR2(100),
    confidence_level_code_value_id VARCHAR2(100),
    explanation_json_path   VARCHAR2(1000),
    created_at              TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_RECO_RESULT PRIMARY KEY (result_id)
);

CREATE TABLE RECO_ITEM (
    item_id          NUMBER       NOT NULL,
    result_id        NUMBER       NOT NULL, -- FK -> RECO_RESULT.result_id
    product_id       NUMBER       NOT NULL, -- FK -> LOAN_PRODUCT.product_id
    matching_score   NUMBER,
    estimated_rate   NUMBER,
    estimated_limit  NUMBER,
    stability_score  NUMBER,
    reason_json_path VARCHAR2(1000),
    rank             NUMBER,
    created_at       TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_RECO_ITEM PRIMARY KEY (item_id)
);

CREATE TABLE RECO_ESTIMATION_DETAIL (
    detail_id      NUMBER       NOT NULL,
    snapshot_id    NUMBER,       -- FK -> USER_CREDIT_SNAPSHOT.snapshot_id (선택)
    item_id        NUMBER       NOT NULL, -- FK -> RECO_ITEM.item_id
    factor_code    VARCHAR2(100),
    factor_name    VARCHAR2(200),
    factor_value   VARCHAR2(1000),
    contribution   NUMBER,
    created_at     TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_RECO_ESTIMATION_DETAIL PRIMARY KEY (detail_id)
);

CREATE TABLE RECO_EXCLUSION_REASON (
    reason_id    NUMBER       NOT NULL,
    result_id    NUMBER       NOT NULL, -- FK -> RECO_RESULT.result_id
    product_id   NUMBER       NOT NULL, -- FK -> LOAN_PRODUCT.product_id
    reason_code  VARCHAR2(100),
    reason_text  VARCHAR2(1000),
    created_at   TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_RECO_EXCLUSION_REASON PRIMARY KEY (reason_id)
);

CREATE TABLE RECO_REJECT_LOG (
    reject_id     NUMBER       NOT NULL,
    request_id    NUMBER       NOT NULL, -- FK -> RECO_REQUEST.request_id
    product_id    NUMBER       NOT NULL, -- FK -> LOAN_PRODUCT.product_id
    reject_code   VARCHAR2(100),
    reject_reason VARCHAR2(1000),
    created_at    TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    CONSTRAINT PK_RECO_REJECT_LOG PRIMARY KEY (reject_id)
);

CREATE TABLE RECO_EVENT_LOG (
    log_id      NUMBER       NOT NULL,
    masked_user_id VARCHAR2(200),
    product_id  NUMBER,       -- FK -> LOAN_PRODUCT.product_id
    event_type_code_value_id VARCHAR2(100),
    occurred_at TIMESTAMP,
    CONSTRAINT PK_RECO_EVENT_LOG PRIMARY KEY (log_id)
);

