-- ADMIN_USER
CREATE TABLE ADMIN_USER (
    admin_id      NUMBER       NOT NULL,
    username      VARCHAR2(100) NOT NULL,
    password_hash VARCHAR2(200) NOT NULL,
    status        VARCHAR2(20) DEFAULT 'ACTIVE' NOT NULL,
